@RestController
@RequestMapping("/otp")
@RequiredArgsConstructor
public class OtpController {

    private final OtpService otpService;

    @PostMapping("/request")
    public ResponseEntity<OtpResponse> requestOtp(@RequestBody @Valid OtpRequest body) {
        return ResponseEntity.ok(otpService.requestOtp(body.getPhone()));
    }

    @PostMapping("/verify")
    public ResponseEntity<VerifyResponse> verifyOtp(@RequestBody @Valid VerifyRequest body) {
        return ResponseEntity.ok(otpService.verifyOtp(body.getRequestId(), body.getOtp()));
    }
}",
        "OtpService.java": "import java.util.*;

@Service
@RequiredArgsConstructor
public class OtpService {

    private final OtpRepository otpRepository;

    public OtpResponse requestOtp(String phone) {
        String otp = generateOtp();
        String requestId = UUID.randomUUID().toString();

        otpRepository.saveOtp(requestId, otp, 300);

        return new OtpResponse(requestId, 300);
    }

    public VerifyResponse verifyOtp(String requestId, String otp) {
        String storedOtp = otpRepository.getOtp(requestId);

        if (storedOtp == null) {
            return new VerifyResponse(false);
        }

        long attempts = otpRepository.incrementAttempts(requestId);

        if (attempts > 3) {
            throw new RuntimeException("Max attempts exceeded");
        }

        boolean verified = storedOtp.equals(otp);
        return new VerifyResponse(verified);
    }

    private String generateOtp() {
        return String.format("%06d", new Random().nextInt(1000000));
    }
}",
        "OtpRepository.java": "@Repository
public interface OtpRepository {
    void saveOtp(String requestId, String otp, long ttlSeconds);
    String getOtp(String requestId);
    long incrementAttempts(String requestId);
}"
    }
}

